unsigned long long run_event_based_simulation_baseline(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0)	
		printf("Beginning event based simulation...\n");

	// Allocate verification array on device
	unsigned long * d_verification;
	gpuErrchk( cudaMalloc((void**)&d_verification, in.lookups * sizeof(unsigned long)) );
	GSD.verification = d_verification;

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;

	xs_lookup_kernel_baseline<<<blocks, threads>>>(in, GSD);
	gpuErrchk( cudaPeekAtLastError() );
	gpuErrchk( cudaDeviceSynchronize() );

	// Reduce on device using thrust
	thrust::device_ptr<unsigned long> d_ptr(d_verification);
	unsigned long long validation_hash = thrust::reduce(
		d_ptr,
		d_ptr + in.lookups,
		0ULL,
		thrust::plus<unsigned long long>()
	);

	gpuErrchk( cudaFree(d_verification) );

	return validation_hash;
}

